const body = $json.body || $json;
const jobId = Array.from({length: 32}, () => Math.random().toString(36)[2]).join('');

return [{
  json: {
    job_id: jobId,
    query: body.query || body.message || '',
    session_id: body.session_id || '',
    document_filter: body.document_filter || null,
    start_time: Date.now()
  }
}];

const searchResponse = $json;
const results = searchResponse.result || searchResponse || [];
const query = $('Generate Query Job ID').first().json.query;

const chunks = (Array.isArray(results) ? results : []).map((r, i) => {
  const payload = r.payload || {};
  return `[Source ${i + 1}: ${payload.file_name || 'Unknown Document'}]\n${payload.text || ''}`;
});

const context = chunks.length > 0
  ? chunks.join('\n\n---\n\n')
  : 'No relevant documents found. Please answer based on your general knowledge and mention that no matching documents were found.';

const sources = (Array.isArray(results) ? results : [])
  .map(r => r.payload?.file_name)
  .filter(Boolean)
  .filter((v, i, a) => a.indexOf(v) === i);

return [{
  json: {
    context: context,
    query: query,
    chunk_count: chunks.length,
    sources: sources
  }
}];

const response = $json;
const content = response.message?.content || response.response || 'I was unable to generate a response. Please try again.';
